class Solution {
    TreeNode* prev = nullptr;
    int maxCnt = 0, cnt = 0;
    vector<int> modes;
    void inorder(TreeNode* n) {
        if (!n) return;
        inorder(n->left);
        cnt = (!prev || n->val == prev->val) ? cnt + 1 : 1;
        if (cnt > maxCnt) { maxCnt = cnt; modes = {n->val}; }
        else if (cnt == maxCnt) modes.push_back(n->val);
        prev = n;
        inorder(n->right);
    }
public:
    vector<int> findMode(TreeNode* root) {
        inorder(root);
        return modes;
    }
};
